```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <memory>
#include <string>
#include <iostream>

namespace test_reaction {

// ============================================
// Data model definitions
// ============================================

class TestTransactionalObserver : public reaction::ObserverNode {
public:
    TestTransactionalObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

    void reset() {
        m_changed = false;
        m_callCount = 0;
    }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto node1 = std::make_shared<TestTransactionalObserver>("Node1");
    auto node2 = std::make_shared<TestTransactionalObserver>("Node2");

    // 2. Get observer graph instance
    auto graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship: node1 observes node2
    graph.addObserver(node1, node2);

    // 4. Notify target and verify relationship works
    node2->valueChanged(true); // Trigger change on node2

    // Verify node1 was notified
    if (!node1->wasChanged()) {
        std::cerr << "Initial relationship verification failed!" << std::endl;
        return false;
    }

    // 5. Reset observer for next test
    node1->reset();
    node2->reset();

    // 6. Attempt transactional update that would create cycle
    // Try to create cycle: node1 observes node2, and node2 observes node1
    bool cycleDetected = false;

    try {
        // 7. Transactional update - this should throw DependencyCycleException
        graph.updateObserversTransactional(node1, {{node2}, {node1}});
    } catch (const reaction::DependencyCycleException& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
        std::cout << "Cycle detected: " << e.what() << std::endl;
    }

    // 8. Notify target again after cycle attempt
    node2->valueChanged(true); // Trigger change on node2 again

    // 9. Verify original relationship is preserved
    if (!node1->wasChanged()) {
        std::cerr << "Original relationship preservation failed!" << std::endl;
        return false;
    }

    // 10. Return success status
    return cycleDetected && node1->wasChanged();
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Observer Creation**: Uses `TestTransactionalObserver` which inherits from `reaction::ObserverNode` and overrides `valueChanged()` to track notification status.

2. **Graph Management**: Properly uses `ObserverGraph::getInstance()` to access the singleton graph instance.

3. **Relationship Setup**: Creates initial observer relationship using `addObserver(node1, node2)` where node1 observes node2.

4. **Notification Verification**: Triggers changes on node2 and verifies node1 receives notifications through `wasChanged()` checks.

5. **State Reset**: Uses the `reset()` method to clear change flags between test phases.

6. **Transactional Update**: Attempts to create a cycle by having node1 observe node2 and node2 observe node1 using `updateObserversTransactional()`.

7. **Exception Handling**: Catches `DependencyCycleException` specifically to detect cycle creation attempts.

8. **Post-Cycle Verification**: Confirms the original relationship still functions correctly after the cycle attempt.

9. **Return Value**: Returns `true` only if both cycle detection and original relationship preservation succeed.

This implementation demonstrates proper usage of the reaction library's observer graph management while testing transactional update capabilities and cycle detection mechanisms.

