```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notifications++;
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    RecordingNode sensor1;
    RecordingNode sensor2;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes with the graph
    graph.addNode(std::make_shared<RecordingNode>(sensor1));
    graph.addNode(std::make_shared<RecordingNode>(sensor2));

    // 4. Set up initial dependency: sensor1 observes sensor2
    sensor1.addOneObserver(std::make_shared<RecordingNode>(sensor2));

    // 5. Save current state of sensor1 for rollback
    auto rollbackFunc = graph.saveNodeStateForRollback(std::make_shared<RecordingNode>(sensor1));

    // 6. Replace dependencies transactionally
    graph.updateObserversTransactional(std::make_shared<RecordingNode>(sensor1), std::make_shared<RecordingNode>(sensor2));

    // 7. Trigger notification on sensor2 (should not affect sensor1 due to new dependency)
    sensor2.valueChanged();

    // 8. Record notification count after second binding
    int countAfterSecondBinding = sensor1.notificationCount();

    // 9. Execute rollback
    rollbackFunc();

    // 10. Trigger notification on sensor2 again
    sensor2.valueChanged();

    // 11. Record notification count after rollback
    int countAfterRollback = sensor1.notificationCount();

    // 12. Return the RollbackObservation struct with both recorded counts
    return RollbackObservation{
        .notificationsAfterSecondBinding = countAfterSecondBinding,
        .notificationsAfterRollback = countAfterRollback
    };
}

}  // namespace test_reaction
