public:
    void valueChanged(bool changed = true) override;
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

CacheStatsSnapshot test_observer_cache_stats() {
    // 1. Create CacheProbeNode instances
    auto node1 = std::make_shared<CacheProbeNode>();
    auto node2 = std::make_shared<CacheProbeNode>();
    auto node3 = std::make_shared<CacheProbeNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.addNode(node1);
    graph.addNode(node2);
    graph.addNode(node3);

    // 4. Set up direct observer relationship: node1 observes node2
    node1->addObserver(node2);

    // 5. Set up transitive observer relationship: node2 observes node3
    node2->addObserver(node3);

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet collectedObservers;

    // 7. Populate cache data by calling collectObservers() on node1
    node1->collectObservers(collectedObservers);

    // 8. Get cache statistics before cleanup
    auto cacheStatsBefore = graph.getCacheStats();
    size_t graphEntriesBeforeCleanup = cacheStatsBefore.graphTraversalCacheStats.totalEntries;

    // 9. Trigger cache cleanup
    graph.triggerCacheCleanup();

    // 10. Get cache statistics after cleanup
    auto cacheStatsAfter = graph.getCacheStats();
    size_t graphEntriesAfterCleanup = cacheStatsAfter.graphTraversalCacheStats.totalEntries;
    double graphHitRatioAfterCleanup = cacheStatsAfter.graphTraversalCacheStats.hitRatio;

    // 11. Close all nodes
    node1->close();
    node2->close();
    node3->close();

    // 12. Return cache stats snapshot
    return CacheStatsSnapshot{
        graphEntriesBeforeCleanup,
        graphEntriesAfterCleanup,
        graphHitRatioAfterCleanup
    };
}

}  // namespace test_reaction
