```cpp
#pragma once

#include <reaction/core/resource.h>
#include <array>

namespace test_reaction {

struct ResourceSBOState {
    bool smallTypeUsesSBO;
    bool largeTypeUsesSBO;
};

ResourceSBOState test_resource_sbo() {
    // 1. Define small type (SmallStruct) that fits in SBO
    struct SmallStruct {
        int x, y;
        SmallStruct(int x = 0, int y = 0) : x(x), y(y) {}
        bool operator==(const SmallStruct& other) const {
            return x == other.x && y == other.y;
        }
        bool operator!=(const SmallStruct& other) const {
            return !(*this == other);
        }
    };

    // 2. Define large type (LargeStruct) that exceeds SBO limits
    struct LargeStruct {
        char data[128];  // 128 bytes - definitely too large for SBO
        LargeStruct(char fill = 'A') {
            std::fill(data, data + 128, fill);
        }
    };

    // 3. Create small resource instance using reaction::Resource
    reaction::Resource<SmallStruct> smallResource;

    // 4. Create large resource instance using reaction::Resource  
    reaction::Resource<LargeStruct> largeResource;

    // 5. Use isUsingSBO() method to check SBO usage for small resource
    bool smallUsesSBO = smallResource.isUsingSBO();

    // 6. Use isUsingSBO() method to check SBO usage for large resource
    bool largeUsesSBO = largeResource.isUsingSBO();

    // 7. Return ResourceSBOState with both boolean values
    return ResourceSBOState{smallUsesSBO, largeUsesSBO};
}

}  // namespace test_reaction
```

